> Pint is an awesome package,

Thanks for the support!

I think that the right way is not to expose the calibration outside the device. Something like:
```python
import pint

ureg = pint.UnitRegistry()

class Device:

    def __init__(position_cal, current_cal):
        self.position_cal = position_cal
        self.current_cal = current_cal

    @property
    def position(self):
        return self._internal_position * self.position_cal

    @property
    def current(self):
        return self._internal_current * self.current_cal

a = Device(0.00123 * ureg.meter, 12.0 * ureg.amperes)
b = Device(0.00123 * ureg.meter, 6.0 * ureg.amperes)
```
or defining a class as you suggested:
```python
import pint

ureg = pint.UnitRegistry()

class Device:

    @property
    def position(self):
        return self._internal_position * self._conv_factors['position_cal']

    @property
    def current(self):
        return self._internal_current * self._conv_factors['current_cal']

class DeviceA(Device):
    _conv_factors = {'position_cal': 0.00123 * ureg.meter, 'current_cal': 12.0 * ureg.amperes}

class DeviceB(Device):
    _conv_factors = {'position_cal': 0.00123 * ureg.meter, 'current_cal':  6.0 * ureg.amperes}

a = DeviceA()
b = DeviceB()
```

I am not sure if this fullfills all your needs but is really clean.

