Support for pattern matching is complete. The pattern matching engine transforms expressions to DFA. It guarantees linear single digit nanosecond execution time per character. Because of its DFA nature it does not support backtracking. The example below matches all ip addresses:

**Pyhton**
```python
with ruleset('match'):
    @when_all(m.ip.matches('((25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)%.){3}(25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)'))
    def approved(c):
        print ('match ip ->{0}'.format(c.m.ip))

    @when_start
    def start(host):
        host.post('match', {'id': 1, 'sid': 1, 'ip': '73.60.124.136'})
        host.post('match', {'id': 2, 'sid': 1, 'ip': '256.60.124.136'})
        host.post('match', {'id': 3, 'sid': 1, 'ip': '250.60.124.256'})
        host.post('match', {'id': 4, 'sid': 1, 'ip': '73.60.124'})
        host.post('match', {'id': 5, 'sid': 1, 'ip': '127.0.0.1'})
```  
**Ruby**
```ruby
Durable.ruleset :match do
  when_all (m.ip.matches("((25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)%.){3}(25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)")) do
    puts "match -> #{m.ip}"
  end
  when_start do
    post :match, {:id => 1, :sid => 1, :ip => "73.60.124.136"}
    post :match, {:id => 2, :sid => 1, :ip => "256.60.124.136"}
    post :match, {:id => 3, :sid => 1, :ip => "250.60.124.256"}
    post :match, {:id => 4, :sid => 1, :ip => "73.60.124"}
    post :match, {:id => 5, :sid => 1, :ip => "127.0.0.1"}
  end
end
```
**Node.js**
```javascript
d.ruleset('match', {
        whenAll: [ m.ip.mt('((25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)%.){3}(25[0-5]|2[0-4][%d]|[01]?[%d][%d]?)') ],
        run: function(c) {
            console.log('match ip ' + c.m.ip);
        }
    },
    function (host) {
        host.post('match', {id: 1, sid: 1, ip: '73.60.124.136'});
        host.post('match', {id: 2, sid: 1, ip: '256.60.124.136'});
        host.post('match', {id: 3, sid: 1, ip: '250.60.124.256'});
        host.post('match', {id: 4, sid: 1, ip: '73.60.124'});
        host.post('match', {id: 5, sid: 1, ip: '127.0.0.1'});
    }
);
```

